import React, { useState, useEffect } from 'react';
import { DollarSign, TrendingUp, PiggyBank, ShoppingCart, AlertTriangle, Plus, Trash2, Edit2, Save, X, Globe, ChevronDown, ChevronRight, Home, Car, Heart, Coffee, Utensils, Gamepad2, Book, Briefcase, Gift, Plane, Camera, Music, Smartphone, Tv, Wifi, Zap, Droplet, Flame, Wind, Sun, Moon, Star, Cloud, TreePine, Flower, Apple, Beer, Pizza, Cake } from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend } from 'recharts';

// Currency configuration
const CURRENCIES = {
  USD: { symbol: '$', position: 'prefix', name: 'US Dollar' },
  EUR: { symbol: '€', position: 'suffix', name: 'Euro' },
  GBP: { symbol: '£', position: 'prefix', name: 'British Pound' },
  CAD: { symbol: 'C$', position: 'prefix', name: 'Canadian Dollar' },
  AUD: { symbol: 'A$', position: 'prefix', name: 'Australian Dollar' },
  NGN: { symbol: '₦', position: 'prefix', name: 'Nigerian Naira' }
};

// Icon mapping
const ICON_MAP = {
  'home': Home,
  'trending-up': TrendingUp,
  'piggy-bank': PiggyBank,
  'shopping-cart': ShoppingCart,
  'alert-triangle': AlertTriangle,
  'car': Car,
  'heart': Heart,
  'coffee': Coffee,
  'utensils': Utensils,
  'gamepad2': Gamepad2,
  'book': Book,
  'briefcase': Briefcase,
  'gift': Gift,
  'plane': Plane,
  'camera': Camera,
  'music': Music,
  'smartphone': Smartphone,
  'tv': Tv,
  'wifi': Wifi,
  'zap': Zap,
  'droplet': Droplet,
  'flame': Flame,
  'wind': Wind,
  'sun': Sun,
  'moon': Moon,
  'star': Star,
  'cloud': Cloud,
  'tree-pine': TreePine,
  'flower': Flower,
  'apple': Apple,
  'beer': Beer,
  'pizza': Pizza,
  'cake': Cake
};

// Available colors for categories
const CATEGORY_COLORS = [
  '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6', '#ef4444',
  '#ec4899', '#06b6d4', '#84cc16', '#f97316', '#6366f1',
  '#14b8a6', '#eab308', '#a855f7', '#f43f5e', '#0ea5e9'
];

const BudgetTracker = () => {
  const [budget, setBudget] = useState({
    amount: '',
    period: 'monthly'
  });

  const [selectedCurrency, setSelectedCurrency] = useState('USD');

  const [categories, setCategories] = useState([
    { id: 1, name: 'Fixed costs', percentage: 50, color: '#3b82f6', icon: 'home', spent: 0, items: [], expanded: false },
    { id: 2, name: 'Investment', percentage: 15, color: '#10b981', icon: 'trending-up', spent: 0, items: [], expanded: false },
    { id: 3, name: 'Short-term savings', percentage: 15, color: '#f59e0b', icon: 'piggy-bank', spent: 0, items: [], expanded: false },
    { id: 4, name: 'Guilt-free spending', percentage: 20, color: '#8b5cf6', icon: 'shopping-cart', spent: 0, items: [], expanded: false },
    { id: 5, name: 'Emergency fund', percentage: 0, color: '#ef4444', icon: 'alert-triangle', spent: 0, items: [], expanded: false }
  ]);

  const [showAddCategory, setShowAddCategory] = useState(false);
  const [newCategory, setNewCategory] = useState({
    name: '',
    percentage: 0,
    color: CATEGORY_COLORS[0],
    icon: 'home'
  });

  const [expenses, setExpenses] = useState([]);
  const [editingCategory, setEditingCategory] = useState(null);
  const [editingItem, setEditingItem] = useState(null);
  const [newExpense, setNewExpense] = useState({
    category: '',
    itemId: null,
    amount: '',
    description: ''
  });
  const [newItem, setNewItem] = useState({
    categoryId: null,
    name: '',
    budgetedAmount: ''
  });
  const [emergencyFundGoal, setEmergencyFundGoal] = useState(10000);

  // Currency formatter utility
  const formatCurrency = (amount) => {
    const currency = CURRENCIES[selectedCurrency];
    const formattedAmount = parseFloat(amount).toFixed(2);

    if (currency.position === 'prefix') {
      return `${currency.symbol}${formattedAmount}`;
    } else {
      return `${formattedAmount}${currency.symbol}`;
    }
  };

  useEffect(() => {
    const savedData = localStorage.getItem('budgetTrackerData');
    if (savedData) {
      const parsed = JSON.parse(savedData);
      setBudget(parsed.budget || { amount: '', period: 'monthly' });
      setCategories(parsed.categories || categories);
      setExpenses(parsed.expenses || []);
      setEmergencyFundGoal(parsed.emergencyFundGoal || 10000);
      setSelectedCurrency(parsed.selectedCurrency || 'USD');
    }
  }, []);

  useEffect(() => {
    const dataToSave = {
      budget,
      categories,
      expenses,
      emergencyFundGoal,
      selectedCurrency
    };
    localStorage.setItem('budgetTrackerData', JSON.stringify(dataToSave));
  }, [budget, categories, expenses, emergencyFundGoal, selectedCurrency]);

  // Calculate category spent from items
  const calculateCategorySpent = (category) => {
    return category.items.reduce((total, item) => total + (item.actualSpent || 0), 0);
  };

  // Calculate category budgeted from items
  const calculateCategoryBudgeted = (category) => {
    return category.items.reduce((total, item) => total + (item.budgetedAmount || 0), 0);
  };

  const calculateBudgetSplit = () => {
    const amount = parseFloat(budget.amount) || 0;
    return categories.map(cat => {
      const catSpent = calculateCategorySpent(cat);
      const catBudgeted = calculateCategoryBudgeted(cat);
      return {
        ...cat,
        allocated: (amount * cat.percentage) / 100,
        budgeted: catBudgeted,
        spent: catSpent,
        remaining: (amount * cat.percentage) / 100 - catSpent
      };
    });
  };

  const updateCategoryPercentage = (categoryId, newPercentage) => {
    const otherCategories = categories.filter(cat => cat.id !== categoryId);
    const otherTotal = otherCategories.reduce((sum, cat) => sum + cat.percentage, 0);
    const maxAllowed = 100 - otherTotal;

    if (newPercentage >= 0 && newPercentage <= maxAllowed) {
      setCategories(prev => prev.map(cat => 
        cat.id === categoryId ? { ...cat, percentage: newPercentage } : cat
      ));
    }
  };

  // Item management functions
  const toggleCategoryExpanded = (categoryId) => {
    setCategories(prev => prev.map(cat => 
      cat.id === categoryId ? { ...cat, expanded: !cat.expanded } : cat
    ));
  };

  const addItem = (categoryId) => {
    if (newItem.name && newItem.budgetedAmount && newItem.categoryId === categoryId) {
      const item = {
        id: Date.now(),
        name: newItem.name,
        budgetedAmount: parseFloat(newItem.budgetedAmount),
        actualSpent: 0
      };

      setCategories(prev => prev.map(cat => 
        cat.id === categoryId 
          ? { ...cat, items: [...cat.items, item] }
          : cat
      ));

      setNewItem({ categoryId: null, name: '', budgetedAmount: '' });
    }
  };

  const updateItem = (categoryId, itemId, updates) => {
    setCategories(prev => prev.map(cat => 
      cat.id === categoryId 
        ? { 
            ...cat, 
            items: cat.items.map(item => 
              item.id === itemId ? { ...item, ...updates } : item
            )
          }
        : cat
    ));
  };

  const deleteItem = (categoryId, itemId) => {
    setCategories(prev => prev.map(cat => 
      cat.id === categoryId 
        ? { ...cat, items: cat.items.filter(item => item.id !== itemId) }
        : cat
    ));
  };

  const addExpense = () => {
    if (newExpense.category && newExpense.amount && newExpense.description) {
      const expense = {
        id: Date.now(),
        category: newExpense.category,
        itemId: newExpense.itemId,
        amount: parseFloat(newExpense.amount),
        description: newExpense.description,
        date: new Date().toISOString()
      };

      setExpenses(prev => [...prev, expense]);

      // Update category spent (kept for backward compatibility)
      setCategories(prev => prev.map(cat => 
        cat.name === newExpense.category 
          ? { ...cat, spent: cat.spent + parseFloat(newExpense.amount) }
          : cat
      ));

      // Update item actual spent if item is specified
      if (newExpense.itemId) {
        setCategories(prev => prev.map(cat => {
          if (cat.name === newExpense.category) {
            return {
              ...cat,
              items: cat.items.map(item => 
                item.id === parseInt(newExpense.itemId) 
                  ? { ...item, actualSpent: (item.actualSpent || 0) + parseFloat(newExpense.amount) }
                  : item
              )
            };
          }
          return cat;
        }));
      }

      setNewExpense({ category: '', itemId: null, amount: '', description: '' });
    }
  };

  const deleteExpense = (expenseId) => {
    const expense = expenses.find(exp => exp.id === expenseId);
    if (expense) {
      setCategories(prev => prev.map(cat => 
        cat.name === expense.category 
          ? { ...cat, spent: cat.spent - expense.amount }
          : cat
      ));
      setExpenses(prev => prev.filter(exp => exp.id !== expenseId));
    }
  };

  const getIcon = (iconName) => {
    const IconComponent = ICON_MAP[iconName] || Home;
    return <IconComponent className="w-5 h-5" />;
  };

  // Category management functions
  const addCategory = () => {
    if (newCategory.name && newCategory.percentage > 0) {
      const otherCategories = categories.filter(cat => cat.id !== newCategory.id);
      const otherTotal = otherCategories.reduce((sum, cat) => sum + cat.percentage, 0);
      const maxAllowed = 100 - otherTotal;

      if (newCategory.percentage <= maxAllowed) {
        const category = {
          id: Date.now(),
          name: newCategory.name,
          percentage: newCategory.percentage,
          color: newCategory.color,
          icon: newCategory.icon,
          spent: 0,
          items: [],
          expanded: false
        };

        setCategories(prev => [...prev, category]);
        setNewCategory({ name: '', percentage: 0, color: CATEGORY_COLORS[0], icon: 'home' });
        setShowAddCategory(false);
      }
    }
  };

  const deleteCategory = (categoryId) => {
    setCategories(prev => prev.filter(cat => cat.id !== categoryId));
  };

  const updateCategory = (categoryId, updates) => {
    setCategories(prev => prev.map(cat => 
      cat.id === categoryId ? { ...cat, ...updates } : cat
    ));
  };

  const budgetSplit = calculateBudgetSplit();
  const totalPercentage = categories.reduce((sum, cat) => sum + cat.percentage, 0);
  const chartData = budgetSplit.map(cat => ({
    name: cat.name,
    value: cat.allocated,
    color: cat.color
  }));

  return (
    <div className="min-h-screen p-4 max-w-7xl mx-auto">
      <div className="mb-8">
        <div className="flex justify-between items-center mb-4">
          <div>
            <h1 className="text-4xl font-bold text-gray-900 mb-2">Budget Tracker</h1>
            <p className="text-gray-600">Automate your finances with smart budget splitting</p>
          </div>
          <div className="flex items-center space-x-2">
            <Globe className="w-4 h-4 text-gray-600" />
            <select
              value={selectedCurrency}
              onChange={(e) => setSelectedCurrency(e.target.value)}
              className="px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent text-sm"
            >
              {Object.entries(CURRENCIES).map(([code, currency]) => (
                <option key={code} value={code}>
                  {currency.symbol} {currency.name}
                </option>
              ))}
            </select>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
        <div className="lg:col-span-2">
          <div className="card">
            <h2 className="text-xl font-semibold mb-4">Budget Setup</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Income/Budget Amount
                </label>
                <input
                  type="number"
                  className="input"
                  placeholder="Enter amount"
                  value={budget.amount}
                  onChange={(e) => setBudget(prev => ({ ...prev, amount: e.target.value }))}
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Time Period
                </label>
                <select
                  className="input"
                  value={budget.period}
                  onChange={(e) => setBudget(prev => ({ ...prev, period: e.target.value }))}
                >
                  <option value="weekly">Weekly</option>
                  <option value="bi-weekly">Bi-weekly</option>
                  <option value="monthly">Monthly</option>
                  <option value="yearly">Yearly</option>
                </select>
              </div>
            </div>

            {totalPercentage !== 100 && (
              <div className="mt-4 p-3 bg-yellow-50 border border-yellow-200 rounded-lg">
                <p className="text-sm text-yellow-800">
                  Categories must total 100%. Current total: {totalPercentage}%
                </p>
              </div>
            )}
          </div>

          <div className="card mt-6">
            <h2 className="text-xl font-semibold mb-4">Categories</h2>
            <div className="space-y-3">
              {categories.map(category => {
                const allocated = (parseFloat(budget.amount) || 0) * category.percentage / 100;
                const categorySpent = calculateCategorySpent(category);
                const categoryBudgeted = calculateCategoryBudgeted(category);
                const remaining = allocated - categorySpent;
                const spentPercentage = allocated > 0 ? (categorySpent / allocated) * 100 : 0;

                return (
                  <div key={category.id} className="border border-gray-200 rounded-lg p-4">
                    <div className="flex items-center justify-between mb-3">
                      <div className="flex items-center space-x-3">
                        <button
                          onClick={() => toggleCategoryExpanded(category.id)}
                          className="p-1 text-gray-600 hover:bg-gray-50 rounded transition-colors"
                        >
                          {category.expanded ? <ChevronDown className="w-4 h-4" /> : <ChevronRight className="w-4 h-4" />}
                        </button>
                        <div style={{ color: category.color }}>
                          {getIcon(category.icon)}
                        </div>
                        <span className="font-medium">{category.name}</span>
                      </div>
                      <div className="flex items-center space-x-2">
                        {editingCategory === category.id ? (
                          <div className="flex items-center space-x-2">
                            <input
                              type="number"
                              className="w-16 px-2 py-1 border border-gray-300 rounded"
                              value={category.percentage}
                              onChange={(e) => updateCategoryPercentage(category.id, parseFloat(e.target.value) || 0)}
                              min="0"
                              max="100"
                            />
                            <span className="text-sm">%</span>
                            <button
                              onClick={() => setEditingCategory(null)}
                              className="p-1 text-green-600 hover:bg-green-50 rounded"
                            >
                              <Save className="w-4 h-4" />
                            </button>
                            <button
                              onClick={() => setEditingCategory(null)}
                              className="p-1 text-red-600 hover:bg-red-50 rounded"
                            >
                              <X className="w-4 h-4" />
                            </button>
                          </div>
                        ) : (
                          <div className="flex items-center space-x-2">
                            <span className="font-semibold">{category.percentage}%</span>
                            <button
                              onClick={() => setEditingCategory(category.id)}
                              className="p-1 text-gray-600 hover:bg-gray-50 rounded"
                            >
                              <Edit2 className="w-4 h-4" />
                            </button>
                          </div>
                        )}
                      </div>
                    </div>

                    <div className="grid grid-cols-3 gap-4 text-sm mb-2">
                      <div>
                        <span className="text-gray-500">Allocated:</span>
                        <span className="ml-1 font-medium">{formatCurrency(allocated)}</span>
                      </div>
                      <div>
                        <span className="text-gray-500">Spent:</span>
                        <span className="ml-1 font-medium">{formatCurrency(categorySpent)}</span>
                      </div>
                      <div>
                        <span className="text-gray-500">Remaining:</span>
                        <span className={`ml-1 font-medium ${remaining < 0 ? 'text-red-600' : 'text-green-600'}`}>
                          {formatCurrency(remaining)}
                        </span>
                      </div>
                    </div>

                    {allocated > 0 && (
                      <div className="progress-bar mb-3">
                        <div
                          className={`progress-fill ${
                            spentPercentage > 100 ? 'bg-red-500' : 
                            spentPercentage > 80 ? 'bg-yellow-500' : 'bg-green-500'
                          }`}
                          style={{ width: `${Math.min(spentPercentage, 100)}%` }}
                        />
                      </div>
                    )}

                    {/* Expandable Items Section */}
                    {category.expanded && (
                      <div className="mt-4 pt-4 border-t border-gray-200">
                        <div className="flex items-center justify-between mb-3">
                          <h4 className="text-sm font-semibold text-gray-700">Budget Items</h4>
                          <button
                            onClick={() => setNewItem({ categoryId: category.id, name: '', budgetedAmount: '' })}
                            className="p-1 text-blue-600 hover:bg-blue-50 rounded"
                          >
                            <Plus className="w-4 h-4" />
                          </button>
                        </div>

                        {/* Add New Item Form */}
                        {newItem.categoryId === category.id && (
                          <div className="mb-3 p-3 bg-gray-50 rounded-lg">
                            <div className="grid grid-cols-2 gap-2 mb-2">
                              <input
                                type="text"
                                placeholder="Item name"
                                className="px-2 py-1 border border-gray-300 rounded text-sm"
                                value={newItem.name}
                                onChange={(e) => setNewItem(prev => ({ ...prev, name: e.target.value }))}
                              />
                              <input
                                type="number"
                                placeholder="Budgeted amount"
                                className="px-2 py-1 border border-gray-300 rounded text-sm"
                                value={newItem.budgetedAmount}
                                onChange={(e) => setNewItem(prev => ({ ...prev, budgetedAmount: e.target.value }))}
                              />
                            </div>
                            <div className="flex space-x-2">
                              <button
                                onClick={() => addItem(category.id)}
                                className="px-2 py-1 bg-blue-600 text-white rounded text-sm hover:bg-blue-700"
                              >
                                Add
                              </button>
                              <button
                                onClick={() => setNewItem({ categoryId: null, name: '', budgetedAmount: '' })}
                                className="px-2 py-1 bg-gray-300 text-gray-700 rounded text-sm hover:bg-gray-400"
                              >
                                Cancel
                              </button>
                            </div>
                          </div>
                        )}

                        {/* Items List */}
                        <div className="space-y-2">
                          {category.items.map(item => {
                            const itemRemaining = item.budgetedAmount - (item.actualSpent || 0);
                            const itemSpentPercentage = item.budgetedAmount > 0 ? ((item.actualSpent || 0) / item.budgetedAmount) * 100 : 0;

                            return (
                              <div key={item.id} className="p-2 bg-gray-50 rounded-lg">
                                {editingItem === item.id ? (
                                  <div className="space-y-2">
                                    <div className="grid grid-cols-2 gap-2">
                                      <input
                                        type="text"
                                        value={item.name}
                                        onChange={(e) => updateItem(category.id, item.id, { name: e.target.value })}
                                        className="px-2 py-1 border border-gray-300 rounded text-sm"
                                      />
                                      <input
                                        type="number"
                                        value={item.budgetedAmount}
                                        onChange={(e) => updateItem(category.id, item.id, { budgetedAmount: parseFloat(e.target.value) || 0 })}
                                        className="px-2 py-1 border border-gray-300 rounded text-sm"
                                      />
                                    </div>
                                    <div className="flex justify-between items-center">
                                      <input
                                        type="number"
                                        placeholder="Actual spent"
                                        value={item.actualSpent || ''}
                                        onChange={(e) => updateItem(category.id, item.id, { actualSpent: parseFloat(e.target.value) || 0 })}
                                        className="px-2 py-1 border border-gray-300 rounded text-sm w-24"
                                      />
                                      <div className="flex space-x-1">
                                        <button
                                          onClick={() => setEditingItem(null)}
                                          className="p-1 text-green-600 hover:bg-green-50 rounded"
                                        >
                                          <Save className="w-3 h-3" />
                                        </button>
                                        <button
                                          onClick={() => setEditingItem(null)}
                                          className="p-1 text-red-600 hover:bg-red-50 rounded"
                                        >
                                          <X className="w-3 h-3" />
                                        </button>
                                      </div>
                                    </div>
                                  </div>
                                ) : (
                                  <div className="flex items-center justify-between">
                                    <div className="flex-1">
                                      <div className="font-medium text-sm">{item.name}</div>
                                      <div className="text-xs text-gray-500">
                                        Budgeted: {formatCurrency(item.budgetedAmount)} | 
                                        Spent: {formatCurrency(item.actualSpent || 0)} | 
                                        <span className={itemRemaining < 0 ? 'text-red-600' : 'text-green-600'}>
                                          Remaining: {formatCurrency(itemRemaining)}
                                        </span>
                                      </div>
                                      {item.budgetedAmount > 0 && (
                                        <div className="w-full bg-gray-200 rounded-full h-1 mt-1">
                                          <div
                                            className={`h-1 rounded-full transition-all duration-300 ${
                                              itemSpentPercentage > 100 ? 'bg-red-500' : 
                                              itemSpentPercentage > 80 ? 'bg-yellow-500' : 'bg-green-500'
                                            }`}
                                            style={{ width: `${Math.min(itemSpentPercentage, 100)}%` }}
                                          />
                                        </div>
                                      )}
                                    </div>
                                    <div className="flex space-x-1 ml-2">
                                      <button
                                        onClick={() => setEditingItem(item.id)}
                                        className="p-1 text-gray-600 hover:bg-gray-50 rounded"
                                      >
                                        <Edit2 className="w-3 h-3" />
                                      </button>
                                      <button
                                        onClick={() => deleteItem(category.id, item.id)}
                                        className="p-1 text-red-600 hover:bg-red-50 rounded"
                                      >
                                        <Trash2 className="w-3 h-3" />
                                      </button>
                                    </div>
                                  </div>
                                )}
                              </div>
                            );
                          })}
                          {category.items.length === 0 && (
                            <div className="text-center text-gray-500 text-sm py-4">
                              No items added yet. Click + to add your first item.
                            </div>
                          )}
                        </div>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        <div className="space-y-6">
          <div className="card">
            <h2 className="text-xl font-semibold mb-4">Budget Overview</h2>
            {parseFloat(budget.amount) > 0 ? (
              <ResponsiveContainer width="100%" height={200}>
                <PieChart>
                  <Pie
                    data={chartData}
                    cx="50%"
                    cy="50%"
                    innerRadius={60}
                    outerRadius={80}
                    paddingAngle={2}
                    dataKey="value"
                  >
                    {chartData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry.color} />
                    ))}
                  </Pie>
                  <Tooltip formatter={(value) => formatCurrency(value)} />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-48 flex items-center justify-center text-gray-500">
                Enter budget amount to see breakdown
              </div>
            )}
          </div>

          <div className="card">
            <h2 className="text-xl font-semibold mb-4">Emergency Fund Goal</h2>
            <div className="space-y-3">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Goal Amount
                </label>
                <input
                  type="number"
                  className="input"
                  value={emergencyFundGoal}
                  onChange={(e) => setEmergencyFundGoal(parseFloat(e.target.value) || 0)}
                />
              </div>
              <div className="space-y-2">
                <div className="flex justify-between text-sm">
                  <span>Current:</span>
                  <span className="font-medium">
                    {formatCurrency(calculateCategorySpent(categories.find(cat => cat.name === 'Emergency fund') || {}))}
                  </span>
                </div>
                <div className="progress-bar">
                  <div
                    className="progress-fill bg-blue-500"
                    style={{
                      width: `${Math.min(
                        (calculateCategorySpent(categories.find(cat => cat.name === 'Emergency fund') || {}) / emergencyFundGoal) * 100,
                        100
                      )}%`
                    }}
                  />
                </div>
                <div className="text-xs text-gray-500 text-center">
                  {(calculateCategorySpent(categories.find(cat => cat.name === 'Emergency fund') || {}) / emergencyFundGoal * 100).toFixed(1)}% complete
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="card">
          <h2 className="text-xl font-semibold mb-4">Add Expense</h2>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Category
              </label>
              <select
                className="input"
                value={newExpense.category}
                onChange={(e) => setNewExpense(prev => ({ ...prev, category: e.target.value }))}
              >
                <option value="">Select category</option>
                {categories.map(cat => (
                  <option key={cat.id} value={cat.name}>{cat.name}</option>
                ))}
              </select>
            </div>
            {newExpense.category && (
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Budget Item (Optional)
                </label>
                <select
                  className="input"
                  value={newExpense.itemId || ''}
                  onChange={(e) => setNewExpense(prev => ({ ...prev, itemId: e.target.value }))}
                >
                  <option value="">No specific item</option>
                  {categories.find(cat => cat.name === newExpense.category)?.items?.map(item => (
                    <option key={item.id} value={item.id}>{item.name}</option>
                  ))}
                </select>
              </div>
            )}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Amount
              </label>
              <input
                type="number"
                className="input"
                placeholder="Enter amount"
                value={newExpense.amount}
                onChange={(e) => setNewExpense(prev => ({ ...prev, amount: e.target.value }))}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Description
              </label>
              <input
                type="text"
                className="input"
                placeholder="What was this expense for?"
                value={newExpense.description}
                onChange={(e) => setNewExpense(prev => ({ ...prev, description: e.target.value }))}
              />
            </div>
            <button
              onClick={addExpense}
              className="btn btn-primary w-full"
            >
              <Plus className="w-4 h-4 inline mr-2" />
              Add Expense
            </button>
          </div>
        </div>

        <div className="card">
          <h2 className="text-xl font-semibold mb-4">Recent Expenses</h2>
          <div className="space-y-2 max-h-64 overflow-y-auto">
            {expenses.length > 0 ? (
              expenses.slice(-10).reverse().map(expense => (
                <div key={expense.id} className="flex items-center justify-between p-2 border border-gray-200 rounded">
                  <div className="flex-1">
                    <div className="font-medium text-sm">{expense.description}</div>
                    <div className="text-xs text-gray-500">{expense.category}</div>
                  </div>
                  <div className="flex items-center space-x-2">
                    <span className="font-medium">{formatCurrency(expense.amount)}</span>
                    <button
                      onClick={() => deleteExpense(expense.id)}
                      className="p-1 text-red-600 hover:bg-red-50 rounded"
                    >
                      <Trash2 className="w-3 h-3" />
                    </button>
                  </div>
                </div>
              ))
            ) : (
              <div className="text-center text-gray-500 py-8">
                No expenses recorded yet
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default BudgetTracker;
